class Solution:
    def checkArray(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        diff = [0] * (n + 1)
        for i in range(n):
            diff[i] += nums[i]
            if i >= k:
                diff[i] -= diff[i - k]
            if i < n - k:
                diff[i + k] -= nums[i]
        for i in range(n):
            if diff[i] != 0:
                return False
        return True
